1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Empty / minimal quote ---
6	  it("empty item list quote returns premium 5 G (processing fee only)", () => {
7	    const scenario = {
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ type: "quote", items: [] }],
10	    };
11	    const { results } = runScenario(scenario);
12	    expect(results[0].premium).toBe(5);
13	  });
14	
15	  // --- Single main items, no modifiers (base + 10% first insurance + 5G fee) ---
16	  // Note: each item in a quote is treated as a first insurance (per spec clarification).
17	  it.todo("quote with one plain sword returns 115 G (100 base + 10 first-insurance + 5 fee)");
18	  it.todo("quote with one plain amulet returns 71 G (60 base + 6 first-insurance + 5 fee)");
19	  it.todo("quote with one plain staff returns 93 G (80 base + 8 first-insurance + 5 fee)");
20	  it.todo("quote with one plain potion returns 49 G (40 base + 4 first-insurance + 5 fee)");
21	
22	  // --- Component base premiums (block-of-3 rule) ---
23	  it.todo("quote with 2 runes returns base premium 50 G before policy modifiers/fee");
24	  it.todo("quote with 3 runes applies block-of-3: base premium 60 G");
25	  it.todo("quote with 4 runes does NOT apply block (requires exactly 3): base premium 100 G");
26	  it.todo("quote with 7 runes returns base premium 175 G (one block of 3 + 4 singles = 60 + 100)");
27	
28	  // --- "Alike" components (clarification: same type, not family) ---
29	  it.todo("quote with 2 runes + 1 moonstone: no block applies (different types), base premium 75 G");
30	  it.todo("quote with 3 runes + 3 moonstones: two separate blocks, base premium 120 G");
31	
32	  // --- Item-level modifiers in isolation ---
33	  it.todo("cursed sword adds 50% curse surcharge on the item's base premium (50 G on a sword)");
34	  it.todo("sword with enchantment exactly 5 adds 30% high-enchantment surcharge (30 G)");
35	  it.todo("sword with enchantment 4 does NOT add high-enchantment surcharge");
36	  it.todo("cursed sword with enchantment 5 stacks both surcharges (+50 G curse + 30 G high-ench)");
37	
38	  // --- Policy-level modifiers in isolation ---
39	  it.todo("customer with exactly 2 years receives 20% loyalty discount on policy base premium");
40	  it.todo("customer with less than 2 years does NOT receive loyalty discount");
41	  it.todo("second quote in scenario applies 15% follow-up contract discount to policy base premium");
42	
43	  // --- Multi-item policy: modifier scope (❓ resolved) ---
44	  it.todo("policy with cursed sword + plain amulet: curse adds 50 G (50% of sword base only), totalling 215 G (100+60 base + 50 curse + 16 first-ins + 5 fee)");
45	
46	  // --- Integration example: Newcomer with cursed sword ---
47	  it.todo("newcomer (0 years) with cursed sword (steel, ench 3) → premium 165 G (100 base + 50 curse + 10 first-ins + 5 fee)");
48	
49	  // --- Integration example: Long-standing customer's second contract ---
50	  it.todo("3-year customer's second quote with cursed sword (ench 7) → premium 160 G (100 + 50 curse + 30 high-ench − 20 loyalty + 10 first-ins − 15 follow-up + 5 fee)");
51	
52	  // --- Rounding (premium rounded UP) ---
53	  it.todo("premium yielding 197.5 G rounds UP to 198 G");
54	  it.todo("intermediate fractional amounts are kept; only the final premium is rounded");
55	
56	  // --- Claim: basic deductible ---
57	  it.todo("claim: regular sword (steel, ench 3) damage 500 G → payout 400 G (500 − 100 deductible)");
58	  it.todo("claim: rune damage 200 G → payout 100 G (full reimbursement minus deductible; no enchantment/material on runes)");
59	
60	  // --- Claim: enchantment ≥ 8 → 50% reimbursement ---
61	  it.todo("claim: steel sword ench 9, damage 1000 G → payout 400 G (500 minus 100 deductible)");
62	  it.todo("claim: dragon sword ench 8, damage 1000 G → payout 400 G (high-ench clause applies first, then deductible)");
63	
64	  // --- Claim: dragon material → full reimbursement ---
65	  it.todo("claim: dragon sword ench 5, damage 800 G → payout 700 G (dragon clause only: full reimbursement minus deductible)");
66	  it.todo("claim: dragon sword ench 9, damage 1000 G → payout 400 G (both clauses apply; 50% rule wins, then deductible)");
67	
68	  // --- Claim: deductible per damage event ---
69	  it.todo("claim: dragon attack damages insured sword (500 G) and amulet (300 G) → payout 600 G (deductible applied once per damaged item)");
70	
71	  // --- Claim: multiple items of the same type ---
72	  it.todo("policy with two swords: insurance sum is 2000 G (2 × 1000)");
73	  it.todo("claim with two sword damages against a 2-sword policy: each entry is its own damage with its own deductible");
74	
75	  // --- Payout rounding (rounded DOWN) ---
76	  it.todo("payout yielding 350.5 G rounds DOWN to 350 G");
77	
78	  // --- Error / edge cases (CLI behaviour) ---
79	  it.todo("quote with unknown item type (e.g. broomstick) exits non-zero with stderr message and no results");
80	  it.todo("claim referencing an item not in the policy (e.g. amulet damaged when only sword insured) exits non-zero with stderr message");
81	  it.todo("claim with negative damage amount (e.g. -200) exits non-zero with stderr message");
82	  it.todo("claim with more damages of a type than the policy covers (e.g. 2 sword damages, 1 sword insured) exits non-zero, whole claim rejected");
83	
84	  // --- CLI scenario integration ---
85	  it.todo("scenario with a quote step followed by a claim step referencing it by policy index returns results array of matching length and order");
86	});
